1	package bead
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"os/exec"
7		"strings"
8	)
9	
10	// ExternalBackend delegates storage to an external tool (bd or br).
11	//
12	// bd and br today have no per-collection scoping in their CLI surface — `bd
13	// list --json` and `bd import` always operate on the tool's primary store.
14	// To preserve the bd/br interchange contract for the default "beads"
15	// collection AND give callers a working path for non-default collections
16	// (notably "beads-archive"), ExternalBackend may carry a JSONL fallback
17	// that handles the read/write/lock plumbing for any collection the tool
18	// cannot natively serve. The default collection always routes through the
19	// external tool; non-default collections route through the fallback when
20	// one is present.
21	type ExternalBackend struct {
22		Tool       string // "bd" or "br"
23		Collection string
24		// fallback handles all Init/Read/Write/Lock calls when set. Populated
25		// by NewExternalBackendWithFallback for non-default collections; nil
26		// for the default collection so the external tool stays authoritative.
27		fallback RawBackend
28	}
29	
30	// Compile-time check: ExternalBackend satisfies RawBackend.
31	var _ RawBackend = (*ExternalBackend)(nil)
32	
33	// NewExternalBackend creates a backend that shells out to the given tool.
34	func NewExternalBackend(tool, collection string) (*ExternalBackend, error) {
35		if _, err := exec.LookPath(tool); err != nil {
36			return nil, fmt.Errorf("bead: backend %s not found in PATH", tool)
37		}
38		return &ExternalBackend{Tool: tool, Collection: collection}, nil
39	}
40	
41	// NewExternalBackendWithFallback constructs an external backend that routes
42	// non-default collections through the supplied fallback Backend. fallback is
43	// ignored for the default collection so the bd/br interchange path stays
44	// unchanged. fallback may be nil when the caller knows the collection is the
45	// default; callers handling arbitrary collections should always supply one.
46	func NewExternalBackendWithFallback(tool, collection string, fallback RawBackend) (*ExternalBackend, error) {
47		e, err := NewExternalBackend(tool, collection)
48		if err != nil {
49			return nil, err
50		}
51		if collection != DefaultCollection {
52			e.fallback = fallback
53		}
54		return e, nil
55	}
56	
57	// Init is a no-op for external backends — they manage their own storage.
58	// The fallback (when set) initializes its JSONL file and lock dir on demand.
59	func (e *ExternalBackend) Init() error {
60		if e.fallback != nil {
61			return e.fallback.Init()
62		}
63		return nil
64	}
65	
66	// ReadAll lists all beads from the external tool.
67	func (e *ExternalBackend) ReadAll() ([]Bead, error) {
68		if e.fallback != nil {
69			return e.fallback.ReadAll()
70		}
71		cmd := exec.Command(e.Tool, "list", "--json")
72		output, err := cmd.Output()
73		if err != nil {
74			return nil, fmt.Errorf("bead: %s list --json: %w", e.Tool, err)
75		}
76	
77		trimmed := strings.TrimSpace(string(output))
78		if trimmed == "" || trimmed == "[]" {
79			return nil, nil
80		}
81	
82		// Try JSON array first
83		if strings.HasPrefix(trimmed, "[") {
84			var raw []json.RawMessage
85			if err := json.Unmarshal([]byte(trimmed), &raw); err != nil {
86				return nil, fmt.Errorf("bead: %s parse: %w", e.Tool, err)
87			}
88			var beads []Bead
89			for _, r := range raw {
90				b, err := unmarshalBead(r)
91				if err != nil {
92					continue
93				}
94				beads = append(beads, b)
95			}
96			return beads, nil
97		}
98	
99		// JSONL fallback
100		var beads []Bead
101		for _, line := range strings.Split(trimmed, "\n") {
102			line = strings.TrimSpace(line)
103			if line == "" {
104				continue
105			}
106			b, err := unmarshalBead([]byte(line))
107			if err != nil {
108				continue
109			}
110			beads = append(beads, b)
111		}
112		return beads, nil
113	}
114	
115	// WriteAll writes all beads back via the external tool.
116	// For bd/br, we export as JSONL and import. This is a full replace.
117	func (e *ExternalBackend) WriteAll(beads []Bead) error {
118		if e.fallback != nil {
119			return e.fallback.WriteAll(beads)
120		}
121		// Build JSONL
122		var sb strings.Builder
123		for _, b := range beads {
124			data, err := marshalBead(b)
125			if err != nil {
126				return fmt.Errorf("bead: marshal for %s: %w", e.Tool, err)
127			}
128			sb.Write(data)
129			sb.WriteByte('\n')
130		}
131	
132		// Pipe to tool's import command
133		cmd := exec.Command(e.Tool, "import", "--from", "jsonl", "--replace", "-")
134		cmd.Stdin = strings.NewReader(sb.String())
135		if output, err := cmd.CombinedOutput(); err != nil {
136			return fmt.Errorf("bead: %s import: %s: %w", e.Tool, string(output), err)
137		}
138		return nil
139	}
140	
141	// WithLock for external backends is a no-op — the tool handles its own
142	// locking. When a JSONL fallback is in play we delegate locking to it so
143	// concurrent writers serialize on the fallback file's lock dir.
144	func (e *ExternalBackend) WithLock(fn func() error) error {
145		if e.fallback != nil {
146			return e.fallback.WithLock(fn)
147		}
148		return fn()
149	}
