1	// Package bead implements the on-disk bead tracker.
2	//
3	// Size envelope (ddx-f8a11202):
4	//
5	// Individual bead fields — description, acceptance, notes, and each event's
6	// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
7	// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
8	// through `bd import`. Writers exceeding the cap are truncated with a
9	// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
10	// preserve the full payload (notably reviewer streams) should persist to a
11	// sidecar artifact under `.ddx/executions/<id>/` and record a path
12	// reference in the event body.
13	//
14	// On the read side, scanners use a 16MB buffer — real-world incidents have
15	// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
16	// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
17	// matches the scanner in the agent package.
18	package bead
19	
20	import (
21		"bufio"
22		"bytes"
23		"context"
24		"crypto/rand"
25		"encoding/hex"
26		"encoding/json"
27		"fmt"
28		"os"
29		"path/filepath"
30		"sort"
31		"strconv"
32		"strings"
33		"time"
34	
35		"github.com/DocumentDrivenDX/ddx/internal/config"
36		gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
37	)
38	
39	// Store manages beads via a pluggable backend.
40	type Store struct {
41		Collection string
42		Dir        string
43		File       string
44		Prefix     string
45		LockDir    string
46		LockWait   time.Duration
47		backend    RawBackend // nil means use built-in JSONL
48	}
49	
50	// Compile-time check: *Store satisfies the high-level Backend interface
51	// declared in backend.go. This is the contract chaos_test.go and (eventually)
52	// cli/cmd callers program against.
53	var _ Backend = (*Store)(nil)
54	
55	type StoreOption func(*Store)
56	
57	// WithCollection selects the logical bead collection. The default collection
58	// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
59	func WithCollection(name string) StoreOption {
60		return func(s *Store) {
61			if cleaned := normalizeCollection(name); cleaned != "" {
62				s.Collection = cleaned
63			}
64		}
65	}
66	
67	// NewStore creates a store with the given directory.
68	// Defaults can be overridden via options or environment.
69	func NewStore(dir string, opts ...StoreOption) *Store {
70		if dir == "" {
71			dir = envOr("DDX_BEAD_DIR", ".ddx")
72		}
73		workingDir := dir
74		if filepath.Base(dir) == ".ddx" {
75			workingDir = filepath.Dir(dir)
76		}
77		prefix := envOr("DDX_BEAD_PREFIX", "")
78		var configBackend string
79		if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil {
80			if prefix == "" && cfg.Bead.IDPrefix != "" {
81				prefix = cfg.Bead.IDPrefix
82			}
83			configBackend = cfg.Bead.Backend
84		}
85		if prefix == "" {
86			prefix = detectPrefix(workingDir)
87		}
88		// Backend selection: env var wins, then config, then jsonl default.
89		backendType := os.Getenv("DDX_BEAD_BACKEND")
90		if backendType == "" {
91			backendType = configBackend
92		}
93		if backendType == "" {
94			backendType = BackendJSONL
95		}
96	
97		s := &Store{
98			Collection: DefaultCollection,
99			Dir:        dir,
100			Prefix:     prefix,
101			LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
102		}
103		for _, opt := range opts {
104			if opt != nil {
105				opt(s)
106			}
107		}
108		spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
109		s.File, s.LockDir = spec.PathsUnder(dir)
110	
111		// Set up external backend if configured. bd/br lack per-collection
112		// scoping in their CLI, so non-default collections (e.g. beads-archive)
113		// route through a JSONL fallback the external backend transparently
114		// delegates to. The default collection always goes straight to bd/br
115		// to preserve the existing interchange contract (schema_compat_test.go,
116		// import/export round-trip).
117		switch backendType {
118		case BackendBD, BackendBR:
119			var fallback RawBackend
120			if s.Collection != DefaultCollection {
121				fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
122			}
123			if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
124				s.backend = ext
125			}
126			// Fall through to JSONL if tool not available
127		}
128	
129		return s
130	}
131	
132	// NewStoreWithBackend creates a store with an explicit RawBackend (for testing).
133	func NewStoreWithBackend(dir string, b RawBackend) *Store {
134		s := NewStore(dir)
135		s.backend = b
136		return s
137	}
138	
139	// NewStoreWithCollection creates a store for a named logical collection.
140	func NewStoreWithCollection(dir, collection string) *Store {
141		return NewStore(dir, WithCollection(collection))
142	}
143	
144	// Init creates the storage directory and file.
145	func (s *Store) Init() error {
146		if s.backend != nil {
147			return s.backend.Init()
148		}
149		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
150			return fmt.Errorf("bead: init dir: %w", err)
151		}
152		f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
153		if err != nil {
154			return fmt.Errorf("bead: init file: %w", err)
155		}
156		return f.Close()
157	}
158	
159	// GenID generates a unique bead ID with the configured prefix.
160	func (s *Store) GenID() (string, error) {
161		b := make([]byte, 4)
162		if _, err := rand.Read(b); err != nil {
163			return "", fmt.Errorf("bead: gen id: %w", err)
164		}
165		return fmt.Sprintf("%s-%s", s.Prefix, hex.EncodeToString(b)), nil
166	}
167	
168	// ReadAll loads all beads from the configured backend.
169	func (s *Store) ReadAll() ([]Bead, error) {
170		return s.ReadAllFiltered(nil)
171	}
172	
173	// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
174	// those for which the predicate returns true. When the predicate is nil every
175	// bead is returned (equivalent to ReadAll). The predicate is applied at the
176	// per-entry parse boundary after fold — matched beads are appended directly to
177	// the return slice without first being held in an intermediate full-corpus
178	// list, so queries that match a small subset avoid materializing the
179	// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
180	func (s *Store) ReadAllFiltered(pred func(Bead) bool) ([]Bead, error) {
181		if s.backend != nil {
182			all, err := s.backend.ReadAll()
183			if err != nil {
184				return nil, err
185			}
186			if pred == nil {
187				return all, nil
188			}
189			out := make([]Bead, 0, len(all))
190			for _, b := range all {
191				if pred(b) {
192					out = append(out, b)
193				}
194			}
195			return out, nil
196		}
197		beads, warnings, err := s.readAllRaw()
198		if err != nil {
199			return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
200		}

200		}
201		beads = foldLatestBeads(beads)
202		for _, warning := range warnings {
203			fmt.Fprintln(os.Stderr, warning)
204		}
205		if len(warnings) > 0 && len(beads) > 0 {
206			repaired, repairErr := s.repairJSONL()
207			if repairErr != nil {
208				return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
209			}
210			if repaired {
211				fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
212			}
213		}
214		if len(beads) == 0 && len(warnings) > 0 {
215			return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
216		}
217		if pred == nil {
218			return beads, nil
219		}
220		out := make([]Bead, 0, len(beads))
221		for _, b := range beads {
222			if pred(b) {
223				out = append(out, b)
224			}
225		}
226		return out, nil
227	}
228	
229	func (s *Store) readAllRaw() ([]Bead, []string, error) {
230		data, err := os.ReadFile(s.File)
231		if os.IsNotExist(err) {
232			return nil, nil, nil
233		}
234		if err != nil {
235			return nil, nil, fmt.Errorf("read: %w", err)
236		}
237		beads, warnings, err := parseBeadJSONL(data)
238		if err != nil {
239			return nil, nil, err
240		}
241		return beads, warnings, nil
242	}
243	
244	func parseBeadJSONL(data []byte) ([]Bead, []string, error) {
245		scanner := bufio.NewScanner(bytes.NewReader(data))
246		// 16MB max line. Real-world extremes observed: 1.46MB bead rows when a
247		// reviewer stream dumped into events[].body, and bd-exported lines stacking
248		// many 65KB fields. bd's upstream per-field cap is 65,535 bytes; an
249		// individual bead with dozens of maxed-out fields fits comfortably in 16MB.
250		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
251	
252		var beads []Bead
253		var warnings []string
254		lineNo := 0
255		for scanner.Scan() {
256			lineNo++
257			line := strings.TrimSpace(scanner.Text())
258			if line == "" {
259				continue
260			}
261			b, err := unmarshalBead([]byte(line))
262			if err != nil {
263				warnings = append(warnings, fmt.Sprintf("bead: read line %d: %v", lineNo, err))
264				continue
265			}
266			beads = append(beads, b)
267		}
268		if err := scanner.Err(); err != nil {
269			return nil, nil, fmt.Errorf("scan jsonl: %w", err)
270		}
271		return beads, warnings, nil
272	}
273	
274	func (s *Store) repairJSONL() (bool, error) {
275		var repaired bool
276		err := s.WithLock(func() error {
277			beads, warnings, err := s.readAllRaw()
278			if err != nil {
279				return err
280			}
281			beads = foldLatestBeads(beads)
282			if len(warnings) == 0 || len(beads) == 0 {
283				return nil
284			}
285			backupPath := s.File + ".bak"
286			backupData, err := os.ReadFile(s.File)
287			if err != nil {
288				return fmt.Errorf("read current file: %w", err)
289			}
290			if err := writeAtomicFile(backupPath, backupData); err != nil {
291				return fmt.Errorf("write backup: %w", err)
292			}
293			if err := s.WriteAll(beads); err != nil {
294				return fmt.Errorf("write repaired file: %w", err)
295			}
296			repaired = true
297			return nil
298		})
299		return repaired, err
300	}
301	
302	func foldLatestBeads(beads []Bead) []Bead {
303		if len(beads) == 0 {
304			return nil
305		}
306	
307		latest := make(map[string]Bead, len(beads))
308		lastSeen := make(map[string]int, len(beads))
309		for i, b := range beads {
310			latest[b.ID] = b
311			lastSeen[b.ID] = i
312		}
313	
314		ids := make([]string, 0, len(latest))
315		for id := range latest {
316			ids = append(ids, id)
317		}
318		sort.Slice(ids, func(i, j int) bool {
319			if lastSeen[ids[i]] != lastSeen[ids[j]] {
320				return lastSeen[ids[i]] < lastSeen[ids[j]]
321			}
322			return ids[i] < ids[j]
323		})
324	
325		out := make([]Bead, 0, len(ids))
326		for _, id := range ids {
327			out = append(out, latest[id])
328		}
329		return out
330	}
331	
332	func (s *Store) readAllLatestRaw() ([]Bead, []string, error) {
333		beads, warnings, err := s.readAllRaw()
334		if err != nil {
335			return nil, nil, err
336		}
337		return foldLatestBeads(beads), warnings, nil
338	}
339	
340	// tmpPath returns a unique temp file path in the same directory as path.
341	// Uses pid + 4 random bytes so concurrent processes don't collide.
342	func tmpPath(path string) (string, error) {
343		b := make([]byte, 4)
344		if _, err := rand.Read(b); err != nil {
345			return "", err
346		}
347		return fmt.Sprintf("%s.tmp-%d-%s", path, os.Getpid(), hex.EncodeToString(b)), nil
348	}
349	
350	func writeAtomicFile(path string, data []byte) error {
351		tmp, err := tmpPath(path)
352		if err != nil {
353			return err
354		}
355		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
356		if err != nil {
357			return err
358		}
359		if _, err := f.Write(data); err != nil {
360			f.Close()
361			_ = os.Remove(tmp)
362			return err
363		}
364		if err := f.Sync(); err != nil {
365			f.Close()
366			_ = os.Remove(tmp)
367			return err
368		}
369		if err := f.Close(); err != nil {
370			_ = os.Remove(tmp)
371			return err
372		}
373		if err := os.Rename(tmp, path); err != nil {
