585		return s.WithLock(func() error {
586			beads, _, err := s.readAllLatestRaw()
587			if err != nil {
588				return err
589			}
590			for i := range beads {
591				if beads[i].ID != id {
592					continue
593				}
594				switch beads[i].Status {
595				case StatusOpen:
596					// normal claim path
597				case StatusInProgress:
598					if !heartbeatIsStale(beads[i].Extra) {
599						return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
600					}
601					// stalled claim — reclaim atomically below
