603					return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
604				}
605				// Refuse claims on beads parked with last_status=push_failed:
606				// the previous attempt landed locally but `git push` was rejected,
607				// so the local commit history exists only on this machine. Re-running
608				// primary work would duplicate or strand commits. The operator must
609				// clear execute-loop-last-status (e.g. by manually pushing or
610				// resetting) before another attempt is allowed.
611				if last, ok := beads[i].Extra["execute-loop-last-status"].(string); ok && last == "push_failed" {
612					detail, _ := beads[i].Extra["execute-loop-last-detail"].(string)
613					if detail != "" {
614						return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed (%s); clear execute-loop-last-status to retry", id, detail)
615					}
616					return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed; clear execute-loop-last-status to retry", id)
617				}
618				if beads[i].Extra == nil {
619					beads[i].Extra = make(map[string]any)
620				}
621				now := time.Now().UTC()
622				beads[i].Status = StatusInProgress
623				beads[i].Owner = assignee
624				beads[i].UpdatedAt = now
625				beads[i].Extra["claimed-at"] = now.Format(time.RFC3339)
626				beads[i].Extra["claimed-pid"] = fmt.Sprintf("%d", os.Getpid())
627				beads[i].Extra["execute-loop-heartbeat-at"] = now.Format(time.RFC3339Nano)
628				if machine != "" {
629					beads[i].Extra["claimed-machine"] = machine
630				}
631				if session != "" {
632					beads[i].Extra["claimed-session"] = session
633				}
634				if worktree != "" {
635					beads[i].Extra["claimed-worktree"] = worktree
636				}
637				if err := s.validateBead(&beads[i]); err != nil {
