649	// Heartbeat refreshes execute-loop-heartbeat-at on a claimed bead. Returns
650	// an error if the bead is no longer in_progress (e.g., reclaimed by another
651	// worker), allowing the caller to stop its heartbeat loop.
652	func (s *Store) Heartbeat(id string) error {
653		return s.WithLock(func() error {
654			beads, _, err := s.readAllLatestRaw()
