676	// heartbeatIsStale returns true if the given bead's Extra map has no
677	// execute-loop-heartbeat-at or one older than HeartbeatTTL.
678	func heartbeatIsStale(extra map[string]any) bool {
679		if extra == nil {
680			return true
681		}
682		raw, ok := extra["execute-loop-heartbeat-at"]
683		if !ok {
684			return true
685		}
686		s, ok := raw.(string)
687		if !ok || s == "" {
688			return true
689		}
690		t, err := time.Parse(time.RFC3339Nano, s)
691		if err != nil {
692			// Fall back to RFC3339 for compatibility with legacy entries written
693			// before sub-second resolution. RFC3339Nano is the current canonical
694			// format used by both ClaimWithOptions and Heartbeat write sites.
695			t, err = time.Parse(time.RFC3339, s)
696			if err != nil {
697				return true
698			}
699		}
700		return time.Since(t) > HeartbeatTTL
701	}
