65		}
66		scanner := bufio.NewScanner(bytes.NewReader(data))
67		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
68		var out []BeadEvent
69		for scanner.Scan() {
70			line := bytes.TrimSpace(scanner.Bytes())
71			if len(line) == 0 {
